import React, { useState } from "react"; 
import axios from "axios"; 

function App() { 
  const [file, setFile] = useState(null); 
  const [progress, setProgress] = useState(0); 
  const [audioUrl, setAudioUrl] = useState(""); 

  const handleDrop = (e) => {
     e.preventDefault();
      setFile(e.dataTransfer.files[0]); };

      const uploadFile = async () => { 
        if (!file) return alert("Drop a PDF first");
        const formData = new FormData();
        formData.append("file", file); 

        const res = await axios.post("http://localhost:8000/upload", formData); 
        const file_id = res.data.file_id; 

        const ws = new WebSocket(`ws://localhost:8000/ws/${file_id}`); 

        ws.onmessage = (event) => { 
          const data = JSON.parse(event.data); 

          if (data.progress) { 
            setProgress(data.progress);
           } 

           if (data.done) { setAudioUrl(`http://localhost:8000${data.audio_url}`); 

           } 
          }; 
        }; 
        return ( 
        <div style={{ textAlign: "center", marginTop: "50px" }}> 
        <h1>PDF → Audio</h1> 
        <div 
        onDrop={handleDrop} onDragOver={(e) => e.preventDefault()} style={{ 
          border: "2px dashed #aaa", 
          padding: "60px", 
          borderRadius: "10px", 
          margin: "20px", 
        }} 
      > 
        {file ? file.name : "Drag & Drop PDF Here"} 
      </div> 
      <button onClick={uploadFile}>Convert</button> 

      <div style={{ marginTop: "20px" }}> 
        <progress value={progress} max="100"></progress> 
        <p>{progress}%</p> 
        </div> 

        {audioUrl && ( 
          <div> 
            <audio controls src={audioUrl}></audio> 
            <br /> 
            <a href={audioUrl} download>Download Audio</a> 
            </div> 
            )} 
            </div> 
          ); 
        } 
export default App;
